results_list <- list(
  best_params = best_params,
  ga_result_summary = summary(ga_result)
)

# Save results to file
saveRDS(results_list, file = paste0(inputDir,"\\ga_result_04_25_26.rds"))

# --- Run Simulation with Optimized Parameters ---

paramCalibrated <- readRDS(paste0(inputDir,"\\ga_result_04_25_26.rds"))
#[[1]]

# Update model parameters
cumba_par$HalfIntSenescence$value<-paramCalibrated$best_params[1]
cumba_par$RootDepthMax$value<-paramCalibrated$best_params[2]
cumba_par$WaterStressSensitivity$value<-paramCalibrated$best_params[3]
cumba_par$RootIncrease$value<-paramCalibrated$best_params[4]
cumba_par$RUE$value<-paramCalibrated$best_params[5]



# Perform final simulation
experiments<- unique(soil$ID)

# Nota: NON serve rifare source('R/Main.R') qui — devtools::load_all()
# all'inizio dello script ha gia' caricato la versione corrente.
# Se hai modificato Main.R dopo l'inizio, basta rilanciare lo script da capo.
devtools::load_all(pkg_root, quiet = TRUE)

results <- list()
 iexp<-experiments[[1]]
for (iexp in experiments) { 
  
  thisExp <- soil %>% 
    filter(ID == iexp)
thisYear<- exp_data$irrigation %>% 
  filter(ID==iexp) %>% 
  slice_head() %>% 
  pull(YEAR)
 
  # aggiorna FC SOLO per questo esperimento
    cumba_par$FieldCapacity$value <- thisExp$FC / 100
  cumba_par$WiltingPoint$value<-thisExp$WP/100
  
  results[[as.character(iexp)]] <- cumba_experiment(
    exp_data$weather %>% 
      mutate(year=year(Date)) %>% 
      filter(year == thisYear), cumba_par,
    estimateRad = TRUE, estimateET0 = TRUE,
    exp_data$irrigation %>% 
      filter(ID==iexp),
    fullOut = TRUE
  )
}

 optimizedSimulation<-do.call(rbind, results)

 # Analyze and visualize correlation
out_calib <- as.data.frame(optimizedSimulation) |> 
  left_join(exp_data$production, by = c("experiment" = "ID")) |>
  group_by(experiment) |>
  slice_tail()


lmYield <- lm(fruitFreshWeightAct*0.01 ~ yield_ref, data = out_calib)
summary(lmYield)



# Scatter plot with regression
scatterYield <- out_calib |>
  ggplot(aes(x = yield_ref, y = fruitFreshWeightAct*0.01)) +
  geom_point() +
  geom_smooth(method = "lm", formula = y ~ x)
scatterYield

library(ggplot2)

lmBrix <- lm(brixAct ~ brix_ref, data = out_calib)
summary(lmBrix)

scatterBrix <- out_calib |>
  ggplot(aes(x = brix_ref, y = brixAct)) +
  geom_point() +
  geom_smooth(method = "lm", formula = y ~ x) 

scatterBrix






# Attach yield only to final row per experiment
optimizedSimulation <- optimizedSimulation %>%
  as.data.frame() %>%
  left_join(exp_data[[4]], by = c("experiment" = "ID")) %>%
  group_by(experiment) %>%
  mutate(
    row_number_within_group = row_number(),
    last_row = row_number_within_group == n(),
    across(starts_with("Y_TOT"), ~ if_else(last_row, ., NA))
  ) %>%
  dplyr::select(-row_number_within_group, -last_row) %>%
  ungroup()

ggplot(optimizedSimulation, aes(x = daysAfterSowing)) +
  #geom_line(aes(x = doy, y = cycleCompletion*8), color = "tomato3", alpha = 1, size = 1) +
  #geom_line(aes(x = doy, y = yield), color = "tomato3", alpha = 1, size = 1) +
     geom_line(aes(x = doy, y = fIntAct*100), color = "tomato3", alpha = 1, size = 1) +
  #geom_line(aes(x = doy, y = et0), color = "pink4", alpha = 1, size = 1) +
  #geom_line(aes(x = doy, y = fIntPot), color = "blue", alpha = 1, size = 1) +
 # geom_line(aes(x = doy, y = fruitsStateAct), color = "tomato3", alpha = 1, size = 1) +
    geom_line(aes(x = doy, y = fruitFreshWeightAct*0.01), color = "black", alpha = 1, size = 1) +
   geom_line(aes(x = doy, y = waterStress*100), color = "blue", alpha = 1, size = .5) +
 # # geom_line(aes(x = doy, y = floweringStateAct*100), color = "black", alpha = 1, size = 2) +
   # geom_line(aes(x = doy, y = brixAct*10), color = "black", alpha = 1, size = .5) +
  # geom_line(aes(x = doy, y = fruitWaterContentAct*100), color = "tomato", alpha = 1, size = .5) +
   geom_line(aes(x = doy, y = kc*100), color = "red", alpha = 1, size = 1) +
  stat_summary(
   aes(x = doy, y = yield_ref),
